import{_ as t,o as e,c as r,a2 as d}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"騎砍2 | 從騎砍1到騎砍2：老玩家轉換指南","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/warband-to-bannerlord.md","filePath":"bannerlord/warband-to-bannerlord.md"}'),l={name:"bannerlord/warband-to-bannerlord.md"};function h(o,a,i,n,s,b){return e(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="騎砍2-從騎砍1到騎砍2-老玩家轉換指南" tabindex="-1">騎砍2 | 從騎砍1到騎砍2：老玩家轉換指南 <a class="header-anchor" href="#騎砍2-從騎砍1到騎砍2-老玩家轉換指南" aria-label="Permalink to &quot;騎砍2 | 從騎砍1到騎砍2：老玩家轉換指南&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>玩了幾百小時騎砍1戰團的老兵，打開騎砍2第一反應通常是：「這不一樣啊？」對，這篇就是幫你快速適應。</p><hr><h2 id="一、最大的改變" tabindex="-1">一、最大的改變 <a class="header-anchor" href="#一、最大的改變" aria-label="Permalink to &quot;一、最大的改變&quot;">​</a></h2><table tabindex="0"><thead><tr><th>系統</th><th>騎砍1</th><th>騎砍2</th></tr></thead><tbody><tr><td>家族</td><td>只有你跟夥伴</td><td>完整家族系統（結婚、生育、接班）</td></tr><tr><td>兵種樹</td><td>固定</td><td>有平民/貴族兩條線，貴族兵強很多</td></tr><tr><td>鍛造</td><td>無</td><td>完整鍛造系統（做武器、熔煉、解鎖配方）</td></tr><tr><td>政策</td><td>無</td><td>王國政策投票系統</td></tr><tr><td>攻城</td><td>單一梯子</td><td>攻城塔、攻城錘、投石機</td></tr><tr><td>圖像</td><td>老舊</td><td>現代化，但更吃效能</td></tr></tbody></table><hr><h2 id="二、騎砍1的習慣要改的" tabindex="-1">二、騎砍1的習慣要改的 <a class="header-anchor" href="#二、騎砍1的習慣要改的" aria-label="Permalink to &quot;二、騎砍1的習慣要改的&quot;">​</a></h2><h3 id="_2-1-單手劍-盾還是最穩" tabindex="-1">2.1 單手劍+盾還是最穩 <a class="header-anchor" href="#_2-1-單手劍-盾還是最穩" aria-label="Permalink to &quot;2.1 單手劍+盾還是最穩&quot;">​</a></h3><p>這點沒變。騎砍1的劍盾流在騎砍2一樣是新手最佳選擇。</p><h3 id="_2-2-騎兵衝鋒變強了" tabindex="-1">2.2 騎兵衝鋒變強了 <a class="header-anchor" href="#_2-2-騎兵衝鋒變強了" aria-label="Permalink to &quot;2.2 騎兵衝鋒變強了&quot;">​</a></h3><p>騎砍2的騎兵衝鋒傷害公式改了，衝起來比騎砍1更痛。但騎兵停下來後比騎砍1脆弱。</p><h3 id="_2-3-賺錢方式更多" tabindex="-1">2.3 賺錢方式更多 <a class="header-anchor" href="#_2-3-賺錢方式更多" aria-label="Permalink to &quot;2.3 賺錢方式更多&quot;">​</a></h3><p>騎砍1主要靠打仗賺錢。騎砍2多了工廠、商隊、鍛造三個被動收入來源。</p><h3 id="_2-4-不要急著加入國家" tabindex="-1">2.4 不要急著加入國家 <a class="header-anchor" href="#_2-4-不要急著加入國家" aria-label="Permalink to &quot;2.4 不要急著加入國家&quot;">​</a></h3><p>騎砍1加入國家是常規操作。騎砍2先當雇傭兵操控各國勢力平衡，比直接當封臣更有效率。</p><hr><h2 id="三、騎砍1沒有的新系統" tabindex="-1">三、騎砍1沒有的新系統 <a class="header-anchor" href="#三、騎砍1沒有的新系統" aria-label="Permalink to &quot;三、騎砍1沒有的新系統&quot;">​</a></h2><h3 id="_3-1-家族與世代" tabindex="-1">3.1 家族與世代 <a class="header-anchor" href="#_3-1-家族與世代" aria-label="Permalink to &quot;3.1 家族與世代&quot;">​</a></h3><p>你的角色會老會死。你需要結婚生孩子培養接班人。騎砍1的「永不退役」思維要改。</p><h3 id="_3-2-政策投票" tabindex="-1">3.2 政策投票 <a class="header-anchor" href="#_3-2-政策投票" aria-label="Permalink to &quot;3.2 政策投票&quot;">​</a></h3><p>王國政策會影響稅收、領主關係、軍事等。騎砍1沒有這個系統。</p><h3 id="_3-3-兵種-tier-差異更大" tabindex="-1">3.3 兵種 Tier 差異更大 <a class="header-anchor" href="#_3-3-兵種-tier-差異更大" aria-label="Permalink to &quot;3.3 兵種 Tier 差異更大&quot;">​</a></h3><p>騎砍1頂級兵差距沒那麼大。騎砍2的 T6 貴族兵可以單挑五個 T3 平民兵。</p><hr><h2 id="四、mod-差異" tabindex="-1">四、MOD 差異 <a class="header-anchor" href="#四、mod-差異" aria-label="Permalink to &quot;四、MOD 差異&quot;">​</a></h2><p>騎砍1的 MOD 數量多、成熟度高（潘德的預言、戰團MOD等）。騎砍2 MOD 生態還在成長，但 2026 年已經很豐富了。</p><hr><h2 id="五、快速轉換懶人包" tabindex="-1">五、快速轉換懶人包 <a class="header-anchor" href="#五、快速轉換懶人包" aria-label="Permalink to &quot;五、快速轉換懶人包&quot;">​</a></h2><ol><li>先玩帝國文化熟悉新系統</li><li>不要直接當封臣，先用雇傭兵身分操控各國平衡</li><li>早點結婚生子（角色會老！）</li><li>善用工廠和商隊獲得被動收入</li><li>看一下 <a href="./mod-recommendations.html">騎砍2 | 2026 必裝 MOD 推薦</a></li></ol><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./beginner-guide.html">騎砍2 | 新手求生指南</a></li><li><a href="./">所有攻略總覽</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',39)])])}const m=t(l,[["render",h]]);export{u as __pageData,m as default};
